<template>
  <header>
    <div class="l-wp | max-w:1440">
      <div class="menu">
        <router-link class="logo" to="/"><img src="./img/logo.svg" alt=""></router-link>
        
        <div class="toggle" :class="{'is-active' : toggle}" @click="menuToggle">
          <div class="toggle__bar"></div>
          <div class="toggle__bar"></div>
          <div class="toggle__bar"></div>
        </div>
        <ul class="list">
          <li class="list__item" v-for="(val, index) in menu" :key="index">
            <a href="javascript:void(0);" class="list__link" @click="toBlock(val.anchor)"><span v-html="val.name"></span></a>
            <!-- <router-link class="list_link" :to="val.url"><span v-html="val.name"></span></router-link> -->
          </li>
        </ul>
      </div>
    </div>
  </header>
</template>

<script setup>
import { defineOptions, ref } from 'vue'
import { useMenu } from '@/use/useMenu'

defineOptions({ name: 'WebsiteHeader' })

// init
const toggle = ref(false)
const menu = ref(useMenu().base)

const menuToggle = () => { toggle.value = !toggle.value }

// 錨點
const toBlock = (i) => {
  // 獲取特定區塊位置
  const targetPosition = document.querySelector(i).offsetTop
  const headerHeight = document.querySelector('header').clientHeight

  const scrollTag =  targetPosition - headerHeight

  window.scrollTo(0, scrollTag)
}

</script>

<style lang="sass" scoped>
@import ./style
</style>
